{
 "level": "A2–B1",
 "intro": "In this topic you will learn <strong>reflexive pronouns</strong> - words that show that the action returns to self.",
 "rules": [
 {
 "label": "-SELF/-SELVES",
 "color": "emerald",
 "text": "<strong>Form:</strong> -self (singular), -selves (plural)",
 "example": "myself, yourself, himself, ourselves, themselves"
 },
 {
 "label": "Reflexive use",
 "color": "blue",
 "text": "<strong>Action on self:</strong> subject = object",
 "example": "I taught myself Spanish. She cut herself."
 },
 {
 "label": "Emphatic use",
 "color": "amber",
 "text": "<strong>Strengthening:</strong> sam, sama, sami",
 "example": "I did it myself. The boss himself came."
 }
 ]
}

{
 "title": "1. Complete table of reflexive pronouns",
 "intro": "All reflexive pronouns end in -self or -selves:",
 "rows": [
 {
 "en": "I → myself",
 "ua": "I → myself",
 "note": "I hurt myself."
 },
 {
 "en": "you → yourself (singular)",
 "ua": "you → yourself (singular)",
 "note": "You did it yourself."
 },
 {
 "en": "he → himself",
 "ua": "he → himself",
 "note": "He cut himself."
 },
 {
 "en": "she → herself",
 "ua": "she → herself",
 "note": "She taught herself."
 },
 {
 "en": "it → itself",
 "ua": "it → itself",
 "note": "The cat cleaned itself."
 },
 {
 "en": "we → ourselves",
 "ua": "we → ourselves",
 "note": "We enjoyed ourselves."
 },
 {
 "en": "you → yourselves (plural)",
 "ua": "you → yourselves (plural)",
 "note": "You all did it yourselves."
 },
 {
 "en": "they → themselves",
 "ua": "they → themselves",
 "note": "They introduced themselves."
 }
 ],
 "warning": "📌 -self = singular, -selves = plural."
}

{
 "title": "2. Reflexive use - action on oneself",
 "sections": [
 {
 "label": "When subject = object",
 "color": "emerald",
 "description": "Reflexive pronouns are used when <strong>the one who acts and the one to whom the action is directed are the same person</strong>.",
 "examples": [
 {
 "en": "I hurt myself.",
 "ua": "I hurt myself."
 },
 {
 "en": "She cut herself with a knife.",
 "ua": "She cut herself with a knife."
 },
 {
 "en": "He taught himself to play guitar.",
 "ua": "He taught himself to play guitar."
 },
 {
 "en": "We enjoyed ourselves at the party: pronouns:",
 "ua": "We enjoyed ourselves at the party: pronouns:"
 },
 {
 "en": "They introduced themselves.",
 "ua": "They introduced themselves."
 }
 ]
 },
 {
 "label": "Common verbs with reflexive pronouns",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "hurt yourself - to injure yourself",
 "ua": "hurt yourself - to injure yourself"
 },
 {
 "en": "cut yourself - to cut yourself",
 "ua": "cut yourself - to cut yourself"
 },
 {
 "en": "teach yourself - to teach yourself",
 "ua": "teach yourself - to teach yourself"
 },
 {
 "en": "enjoy yourself - enjoy yourself",
 "ua": "enjoy yourself - enjoy yourself"
 },
 {
 "en": "introduce yourself",
 "ua": "introduce yourself"
 },
 {
 "en": "help yourself - treat yourself",
 "ua": "help yourself - treat yourself"
 }
 ]
 },
 {
 "label": "Look at yourself",
 "color": "purple",
 "description": "With verbs like <strong>look at, talk to, believe in</strong> we also use reflexive.",
 "examples": [
 {
 "en": "Look at yourself in the mirror.",
 "ua": "Look at yourself in the mirror."
 },
 {
 "en": "She talks to herself sometimes.",
 "ua": "She talks to herself sometimes."
 },
 {
 "en": "You should believe in yourself.",
 "ua": "You should believe in yourself."
 },
 {
 "en": "They laughed at themselves.",
 "ua": "They laughed at themselves."
 }
 ]
 }
 ]
}

{
 "title": "3. Emphatic use - reinforcement (himself, herself, themselves)",
 "sections": [
 {
 "label": "For reinforcement",
 "color": "amber",
 "description": "Reverse pronouns are also used for <strong>reinforcement</strong> - to emphasize that it was this person who performed the action (not someone else).",
 "examples": [
 {
 "en": "I did it myself.",
 "ua": "I did it myself."
 },
 {
 "en": "She cooked dinner herself.",
 "ua": "She cooked dinner herself."
 },
 {
 "en": "The president himself came to the event.",
 "ua": "The president himself came to the event."
 },
 {
 "en": "We built this house ourselves.",
 "ua": "We built this house ourselves."
 }
 ]
 },
 {
 "label": "Emphatic position",
 "color": "blue",
 "description": "In emphatic use, the reflexive pronoun can stand <strong>immediately after the subject</strong> or <strong>at the end of the sentence</strong>.",
 "examples": [
 {
 "en": "I myself saw it. = I saw it myself.",
 "ua": "I myself saw it. = I saw it myself."
 },
 {
 "en": "The boss himself called. = The boss called himself.",
 "ua": "The boss himself called. = The boss called himself."
 },
 {
 "en": "She herself told me. = She told me herself.",
 "ua": "She herself told me. = She told me herself."
 }
 ],
 "note": "📌 Both positions are correct - after the subject or at the end."
 },
 {
 "label": "Difference: reflexive vs emphatic",
 "color": "purple",
 "description": "<strong>Reflexive</strong> is obligatory (action on oneself). <strong>Emphatic</strong> is optional (for emphasis).",
 "examples": [
 {
 "en": "I hurt myself. (reflexive - mandatory)",
 "ua": "I hurt myself. (reflexive - mandatory)"
 },
 {
 "en": "I did it myself. (emphatic - possible: I did it)",
 "ua": "I did it myself. (emphatic - possible: I did it)"
 }
 ],
 "note": "Reflexive - necessary. Emphatic - for emphasis."
 }
 ]
}

{
 "title": "4. By yourself, for yourself, to yourself",
 "sections": [
 {
 "label": "By yourself - independently",
 "color": "emerald",
 "description": "<strong>By + reflexive</strong> means <strong>independently</strong> (without help) or <strong>alone</strong> (alone).",
 "examples": [
 {
 "en": "I did it by myself.",
 "ua": "I did it by myself."
 },
 {
 "en": "She lives by herself.",
 "ua": "She lives by herself."
 },
 {
 "en": "Can you do it by yourself?",
 "ua": "Can you do it by yourself?"
 },
 {
 "en": "He went to the cinema by himself.",
 "ua": "He went to the cinema by himself."
 }
 ],
 "note": "📌 By myself = alone or without help."
 },
 {
 "label": "For yourself",
 "color": "blue",
 "description": "<strong>For + reflexive</strong> means <strong>for yourself</strong>.",
 "examples": [
 {
 "en": "Buy something for yourself.",
 "ua": "Buy something for yourself."
 },
 {
 "en": "Keep it for yourself.",
 "ua": "Keep it for yourself."
 },
 {
 "en": "I made this cake for myself.",
 "ua": "I made this cake for myself."
 }
 ]
 },
 {
 "label": "To yourself — to yourself, for yourself",
 "color": "sky",
 "description": "<strong>To + reflexive</strong> often in expressions like 'say to yourself', 'keep to yourself'.",
 "examples": [
 {
 "en": "Keep it to yourself.",
 "ua": "Keep it to yourself."
 },
 {
 "en": "I said to myself...",
 "ua": "I said to myself..."
 },
 {
 "en": "She whispered to herself.",
 "ua": "She whispered to herself."
 }
 ]
 }
 ]
}

{
 "title": "5. When NOT to use the reflexive",
 "sections": [
 {
 "label": "With some verbs it is NOT necessary",
 "color": "rose",
 "description": "Some verbs in English <strong>DO NOT need</strong> a reflexive pronoun (unlike Ukrainian!).",
 "examples": [
 {
 "en": "I feel good. (✓)",
 "ua": "I feel good. (✓)"
 },
 {
 "en": "I feel myself good. (✗)",
 "ua": "I feel myself good. (✗)"
 },
 {
 "en": "She got dressed. (✓)",
 "ua": "She got dressed. (✓)"
 },
 {
 "en": "She dressed herself. (✗ in modern English)",
 "ua": "She dressed herself. (✗ in modern English)"
 },
 {
 "en": "We met at 5 pm. (✓)",
 "ua": "We met at 5 pm. (✓)"
 },
 {
 "en": "We met ourselves. (✗)",
 "ua": "We met ourselves. (✗)"
 }
 ],
 "note": "📌 Feel, get dressed, meet, wash, shave — no reflexive!"
 },
 {
 "label": "Wash, shave — special case",
 "color": "amber",
 "description": "<strong>Wash</strong> and <strong>shave</strong> usually without reflexive, but can be added for reinforcement.",
 "examples": [
 {
 "en": "I wash every day. (✓ of course)",
 "ua": "I wash every day. (✓ of course)"
 },
 {
 "en": "I wash myself every day. (✓ with reinforcement)",
 "ua": "I wash myself every day. (✓ with reinforcement)"
 },
 {
 "en": "He shaves in the morning. (✓)",
 "ua": "He shaves in the morning. (✓)"
 },
 {
 "en": "The baby can wash himself. (✓)",
 "ua": "The baby can wash himself. (✓)"
 }
 ],
 "note": "Wash/shave without reflexive is the norm. With reflexive - for emphasis."
 },
 {
 "label": "When the object is another person",
 "color": "purple",
 "description": "If the action is aimed at <strong>another person</strong> (not at oneself) - do NOT use reflexive.",
 "examples": [
 {
 "en": "She washed the baby. (✓)",
 "ua": "She washed the baby. (✓)"
 },
 {
 "en": "She washed herself. (✓)",
 "ua": "She washed herself. (✓)"
 },
 {
 "en": "I hurt my friend. (✓)",
 "ua": "I hurt my friend. (✓)"
 },
 {
 "en": "I hurt myself. (✓)",
 "ua": "I hurt myself. (✓)"
 }
 ],
 "note": "Reflexive only when acting on SELF, not others!"
 }
 ]
}

{
 "title": "6. Each other vs Reflexive",
 "sections": [
 {
 "label": "Each other - each other (mutually)",
 "color": "blue",
 "description": "<strong>Each other</strong> shows mutual action (A → B and B → A). <strong>Reflexive</strong> — action on oneself (A → A).",
 "examples": [
 {
 "en": "They love each other.",
 "ua": "They love each other."
 },
 {
 "en": "They love themselves.",
 "ua": "They love themselves."
 },
 {
 "en": "We help each other.",
 "ua": "We help each other."
 },
 {
 "en": "We help ourselves.",
 "ua": "We help ourselves."
 }
 ],
 "note": "📌 Each other = mutual. Reflexive = to himself."
 },
 {
 "label": "Examples of the difference",
 "color": "sky",
 "description": "The context shows the difference:",
 "examples": [
 {
 "en": "They looked at themselves in the mirror.",
 "ua": "They looked at themselves in the mirror."
 },
 {
 "en": "They looked at each other.",
 "ua": "They looked at each other."
 },
 {
 "en": "Talk to yourself! (reflexive)",
 "ua": "Talk to yourself! (reflexive)"
 },
 {
 "en": "Talk to each other! (reciprocal)",
 "ua": "Talk to each other! (reciprocal)"
 }
 ]
 }
 ]
}

{
 "title": "7. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Extra reflexive with feel, meet, wash.",
 "wrong": "I feel myself good. / We met ourselves at 5.",
 "right": "​​​​ <span class=\"font-mono\">I feel good. / We met at 5.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Incorrect form (hisself, themselves).",
 "wrong": "He did it himself. / They enjoyed themselves.",
 "right": "​​​​ <span class=\"font-mono\">He did it himself. / They enjoyed themselves.</span>"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Confusion of themselves and each other.",
 "wrong": "They love themselves. (when mutual)",
 "right": " ✅ <span class=\"font-mono\">They love each other.</span> (each other)"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Omission of reflexive when it is needed.",
 "wrong": "I hurt yesterday. / She taught Spanish.",
 "right": "​​​​ <span class=\"font-mono\">I hurt myself. / She taught herself Spanish.</span>"
 }
 ]
}

{
 "title": "9. Practice",
 "select_title": "Exercise 1. Choose the correct form",
 "select_intro": "Fill in the blanks with the correct reflexive pronoun or leave it blank.",
 "selects": [
 {
 "label": "I hurt ___ playing football. (myself / me)",
 "prompt": "What form?"
 },
 {
 "label": "She taught ___ Spanish. (her / herself)",
 "prompt": "What form?"
 },
 {
 "label": "I feel ___ good today. (— / myself)",
 "prompt": "Need reflexive?"
 },
 {
 "label": "We enjoyed ___ at the party. (us / ourselves)",
 "prompt": "What form?"
 },
 {
 "label": "They met ___ at the station. (— / themselves)",
 "prompt": "Required reflexive?"
 }
 ],
 "options": [
 "myself",
 "yourself",
 "himself",
 "herself",
 "ourselves",
 "themselves",
 "—"
 ],
 "input_title": "Exercise 2. Fill in the blanks",
 "input_intro": "Write the correct reflexive pronoun.",
 "inputs": [
 {
 "before": "I did it ___. (myself)",
 "after": "→"
 },
 {
 "before": "She cut ___ with a knife. (cut herself)",
 "after": "→"
 },
 {
 "before": "They introduced ___. (introduced)",
 "after": "→"
 },
 {
 "before": "We enjoyed ___ at the concert. (had a good time)",
 "after": "→"
 }
 ],
 "rephrase_title": "Exercise 3. Error correction",
 "rephrase_intro": "Find and correct the error with the reflexive pronouns.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "I feel myself good.",
 "example_target": "I feel good."
 },
 {
 "original": "1. He did it himself.",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. They enjoyed themselves.",
 "placeholder": "Fix the error"
 },
 {
 "original": "3. We met ourselves at 5.",
 "placeholder": "Correct an error"
 }
 ]
}

